import {
  type KeyboardEvent,
  useCallback,
  useEffect,
  useId,
  useMemo,
  useRef,
  useState,
} from "react";
import { Command as CommandPrimitive } from "cmdk";
import { cn } from "../../lib/utils";
import {
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
} from "../ui/command";
import { Label } from "../ui/label";
import { Skeleton } from "../ui/skeleton";

export type Option = Record<"value" | "label", string> & Record<string, string>;

type AutoCompleteProps = {
  id?: string;
  label: string;
  options: Option[];
  emptyMessage: string;
  value?: string;
  onValueChange?: (value: Option) => void;
  onInputChange?: (value: string) => void;
  isLoading?: boolean;
  disabled?: boolean;
  placeholder?: string;
  showRequired?: boolean;
  required?: boolean;
  name?: string;
};

export const AutoComplete = ({
  id,
  label,
  options,
  name,
  placeholder,
  emptyMessage,
  value,
  onValueChange,
  onInputChange,
  disabled,
  isLoading = false,
  showRequired = true,
  required = true,
}: AutoCompleteProps) => {
  const rootRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const [isOpen, setOpen] = useState(false);
  const [isNavigatingOptions, setIsNavigatingOptions] = useState(false);
  const [inputValue, setInputValue] = useState<string>(value || "");
  const fallbackId = useId();
  const inputId = id ?? name ?? fallbackId;

  // Update inputValue when value prop changes
  useEffect(() => {
    setInputValue(value || "");
  }, [value]);

  const labelContent = useMemo(() => {
    return (
      <>
        {label}
        {showRequired ? (
          required ? (
            <span className="text-xs text-neutral-500">required</span>
          ) : (
            <span className="text-xs font-normal text-neutral-500">
              optional
            </span>
          )
        ) : null}
      </>
    );
  }, [label, required, showRequired]);

  const handleInputChange = useCallback(
    (value: string) => {
      setInputValue(value);
      setIsNavigatingOptions(false);
      onInputChange?.(value);
    },
    [onInputChange],
  );

  const handleSelectOption = useCallback(
    (selectedOption: Option) => {
      onValueChange?.(selectedOption);

      // This is a hack to prevent the input from being focused after the user selects an option
      setTimeout(() => {
        inputRef?.current?.blur();
      }, 0);
    },
    [onValueChange],
  );

  const getSelectedOption = useCallback(() => {
    const selectedItem = rootRef.current?.querySelector<HTMLElement>(
      '[cmdk-item][aria-selected="true"]',
    );
    const selectedValue =
      selectedItem?.getAttribute("data-value") ?? selectedItem?.textContent;
    if (!selectedValue) {
      return undefined;
    }

    return options.find(
      (option) =>
        option.label === selectedValue || option.value === selectedValue,
    );
  }, [options]);

  const handleKeyDown = useCallback(
    (event: KeyboardEvent<HTMLDivElement>) => {
      const input = inputRef.current;
      if (!input) {
        return;
      }

      if (!isOpen) {
        setOpen(true);
      }

      if (event.key === "ArrowDown" || event.key === "ArrowUp") {
        setIsNavigatingOptions(true);
        return;
      }

      if (event.key === "Escape") {
        input.blur();
        return;
      }

      const shouldSelectWithSpace =
        event.key === " " && isNavigatingOptions && isOpen;
      const shouldSelectWithEnter = event.key === "Enter" && isOpen;

      if (shouldSelectWithSpace || shouldSelectWithEnter) {
        const selectedOption = getSelectedOption();
        if (selectedOption) {
          event.preventDefault();
          handleSelectOption(selectedOption);
          return;
        }
      }

      if (event.key === "Enter" && input.value !== "") {
        const optionToSelect = options.find(
          (option) => option.label === input.value,
        );
        if (optionToSelect) {
          event.preventDefault();
          handleSelectOption(optionToSelect);
        }
      }
    },
