import {
  MaskedPatternInput,
  type MaskedPatternInputProps,
} from "../masked-number-input";
import { Button } from "../ui/button";
import { Calendar } from "../ui/calendar";

const DEFAULT_START_DATE = new Date(1900, 0, 1);
const DEFAULT_END_DATE = addYears(new Date(), 10);

export type DateInputProps = Omit<
  MaskedPatternInputProps,
  "onChange" | "value"
> & {
  startDate?: Date;
  endDate?: Date;
  defaultValue?: Date;
  placeholder?: string;
  onChange?: (value: string) => void;
  mode?: "single" | "multiple" | "range";
  required?: boolean;
  value?: string;
  calendarProps?: PropsBase & PropsSingle;
};

export const DateInput = ({
  startDate = DEFAULT_START_DATE,
  endDate = DEFAULT_END_DATE,
  defaultValue,
  placeholder = "MM/DD/YYYY",
  onChange,
  mode = "single",
  calendarProps,
  value: inputValue,
  ...inputProps
}: DateInputProps) => {
  const [open, setOpen] = useState(false);
  const [date, setDate] = useState<Date | undefined>(defaultValue ?? undefined);
  const [month, setMonth] = useState<Date | undefined>(date);
  const [value, setValue] = useState<string | undefined>(inputValue);

  return (
    <div className="flex flex-col gap-3">
      <div className="flex relative gap-2">
        <MaskedPatternInput
          className="pr-10 bg-background"
          format="##/##/####"
          onChange={(e) => {
            setValue(e.target.value);
            onChange?.(e.target.value);
          }}
          onKeyDown={(e) => {
            if (e.key === "ArrowDown") {
              e.preventDefault();
              setOpen(true);
            }
          }}
          placeholder={placeholder}
          value={inputValue ?? value}
          {...inputProps}
        />
        <Popover onOpenChange={setOpen} open={open}>
          <PopoverTrigger asChild>
            <Button
              className="absolute right-2 top-1/2 p-0 -translate-y-1/2 size-6"
              id="date-picker"
              variant="ghost"
            >
              <CalendarIcon className="size-4 text-foreground" />
              <span className="sr-only">Select date</span>
            </Button>
          </PopoverTrigger>
          <PopoverContent
            align="end"
            alignOffset={-8}
            className="overflow-hidden p-0 w-auto"
            sideOffset={10}
          >
            {mode === "single" ? (
              <Calendar
                captionLayout="dropdown"
                disabled={calendarProps?.disabled}
                endMonth={endDate}
                mode="single"
                month={month}
                onMonthChange={setMonth}
                onSelect={(date) => {
                  setDate(date);
                  setValue(formatDateTime(date, { outputFormat: "MDY" }));
                  setOpen(false);
                  onChange?.(formatDateTime(date, { outputFormat: "MDY" }));
                }}
                selected={date}
                startMonth={startDate}
                {...calendarProps}
              />
            ) : null}
            {/* TODO: Add multiple and range modes when needed */}
          </PopoverContent>
        </Popover>
      </div>
    </div>
  );
};

